def cache_get(key):
    try:
        value = cache.get(key)
        if value is None:
            return None
        if isinstance(value, bytes):
            value = value.decode("utf-8")
        return json.loads(value)
    except Exception:
        return None


def cache_set(key, value, ttl):
    try:
        cache.set(key, json.dumps(value), expire=ttl)
        return True
    except Exception:
        return False


def cache_delete(key):
    try:
        cache.delete(key)
        return True
    except Exception:
        return False


def make_cache_key(prefix, payload):
    raw = json.dumps(payload, sort_keys=True, separators=(",", ":"))
    digest = hashlib.sha256(raw.encode("utf-8")).hexdigest()
    return f"{prefix}:{digest}"


def fetch_item_from_db(item_id):
    cache_key = make_cache_key("db:item", {"id": item_id})
    cached = cache_get(cache_key)
    if cached is not None:
        return cached, True

    conn = get_db()
    cur = conn.cursor()
    cur.execute("SELECT id, name, value, updated_at FROM items WHERE id = ?", (item_id,))
    row = cur.fetchone()
    conn.close()

    result = dict(row) if row else None
    if result is not None:
        cache_set(cache_key, result, DB_QUERY_TTL)
    return result, False


def fetch_all_items_from_db(limit=100):
    cache_key = make_cache_key("db:items", {"limit": limit})
    cached = cache_get(cache_key)
    if cached is not None:
        return cached, True

    conn = get_db()
    cur = conn.cursor()
    cur.execute(
        "SELECT id, name, value, updated_at FROM items ORDER BY id ASC LIMIT ?",
        (limit,),
    )
    rows = [dict(r) for r in cur.fetchall()]
    conn.close()

    cache_set(cache_key, rows, DB_QUERY_TTL)
    return rows, False


def api_response_cache(ttl=API_RESPONSE_TTL):
    def decorator(fn):
        @wraps(fn)
        def wrapper(*args, **kwargs):
            payload = {
                "path": request.path,
                "args": request.args.to_dict(flat=False),
                "view_args": kwargs,
                "method": request.method,
            }
            cache_key = make_cache_key("api:response", payload)
            cached = cache_get(cache_key)
            if cached is not None:
                return jsonify({"cached": True, "data": cached})

            response = fn(*args, **kwargs)
            if isinstance(response, tuple):
                body, status = response
            else:
                body, status = response, 200

            if status == 200:
                data_to_cache = body.get_json() if hasattr(body, "get_json") else body
                cache_set(cache_key, data_to_cache, ttl)

            return response

        return wrapper

    return decorator


@app.route("/health", methods=["GET"])
def health():
    memcached_ok = True
    try:
        cache.set("healthcheck", "ok", expire=5)
        memcached_ok = cache.get("healthcheck") is not None
    except Exception:
        memcached_ok = False

    return jsonify(
        {
            "status": "ok",
            "memcached": "up" if memcached_ok else "down",
        }
    )


