@app.route("/items", methods=["POST"])
def create_item():
    data = request.get_json(silent=True) or {}
    name = data.get("name")
    value = data.get("value")

    if not name or not value:
        return jsonify({"error": "name and value are required"}), 400

    now = int(time.time())
    conn = get_db()
    cur = conn.cursor()
    cur.execute(
        "INSERT INTO items (name, value, updated_at) VALUES (?, ?, ?)",
        (name, value, now),
    )
    item_id = cur.lastrowid
    conn.commit()
    conn.close()

    cache_delete(make_cache_key("db:item", {"id": item_id}))
    return jsonify(
        {
            "id": item_id,
            "name": name,
            "value": value,
            "updated_at": now,
        }
    ), 201


@app.route("/items/<int:item_id>", methods=["PUT"])
def update_item(item_id):
    data = request.get_json(silent=True) or {}
    name = data.get("name")
    value = data.get("value")

    if not name or not value:
        return jsonify({"error": "name and value are required"}), 400

    now = int(time.time())
    conn = get_db()
    cur = conn.cursor()
    cur.execute(
        "UPDATE items SET name = ?, value = ?, updated_at = ? WHERE id = ?",
        (name, value, now, item_id),
    )
    updated = cur.rowcount
    conn.commit()
    conn.close()

    if updated == 0:
        return jsonify({"error": "Item not found"}), 404

    cache_delete(make_cache_key("db:item", {"id": item_id}))
    return jsonify(
        {
            "id": item_id,
            "name": name,
            "value": value,
            "updated_at": now,
        }
    )


